(1, 2, 1, 'Dark mode support', 'It would be great to have a dark mode option for the application. This would help reduce eye strain during night usage.', 'open', 99, 99, 0, 33, 3204, 0, NULL, '2026-05-15 22:10:30', '2026-06-15 04:24:38'),
(2, 3, 2, 'Custom keyboard shortcuts', 'Allow users to customize keyboard shortcuts for frequently used actions. This would significantly speed up workflow.', 'planned', 70, 78, 8, 18, 2402, 0, NULL, '2026-06-04 20:10:30', '2026-06-15 03:32:22'),
(3, 4, 1, 'Mobile app for iOS and Android', 'A mobile app would make it easier to stay updated on feedback and roadmap from anywhere.', 'under_review', 91, 95, 4, 42, 4100, 0, NULL, '2026-06-09 21:10:30', '2026-06-15 01:29:44'),
(4, 5, 2, 'Advanced search filters', 'More advanced filtering options in search to quickly find relevant feedback based on multiple criteria.', 'planned', 48, 54, 6, 27, 1804, 0, NULL, '2026-06-14 23:10:30', '2026-06-15 04:35:01'),
(5, 6, 1, 'Integrate with Slack', 'It would be great to receive notifications and updates directly in Slack so the team stays informed.', 'planned', 36, 48, 12, 22, 2200, 0, NULL, '2026-06-06 23:10:30', '2026-06-15 01:10:32'),
(6, 2, 2, 'Autosave draft feedback', 'Save partially written feedback drafts automatically so users do not lose content when they navigate away or refresh.', 'open', 25, 28, 3, 10, 1700, 1, NULL, '2026-06-14 01:10:30', '2026-06-15 04:46:32'),
(7, 3, 3, 'Bug: notifications still show after read', 'Even after marking notifications as read, the indicator remains active in the header. Steps to reproduce are included.', 'open', 5, 40, 35, 38, 2600, 0, NULL, '2026-06-02 19:10:30', '2026-06-15 01:10:32'),
(8, 5, 4, 'Improve onboarding checklist', 'A more detailed onboarding checklist would help new users understand key actions and first steps.', 'planned', 25, 30, 5, 14, 1600, 0, NULL, '2026-06-10 23:10:30', '2026-06-15 01:10:32'),
(9, 4, 1, 'Allow markdown notes in feedback', 'Support markdown formatting in feedback descriptions and comments to make issue reports easier to scan.', 'open', 61, 68, 7, 20, 2504, 0, NULL, '2026-06-14 05:10:30', '2026-06-15 04:46:28'),
(10, 6, 1, 'Dark mode schedule', 'Allow dark mode to activate automatically based on local sunrise and sunset times.', 'open', 20, 22, 2, 9, 900, 0, NULL, '2026-06-14 11:10:30', '2026-06-15 01:10:33'),
(11, 5, 3, 'Search result relevance feels off', 'Some search results return unrelated items. I often need to refine the query multiple times.', 'open', 11, 15, 4, 31, 1900, 0, NULL, '2026-06-05 17:10:30', '2026-06-15 01:10:33'),
(12, 3, 3, 'Temporary fix for slow loading dashboard', 'The dashboard becomes slow when many cards are loaded. A temporary workaround would help until the backend query is optimized.', 'open', 34, 41, 7, 24, 2004, 0, NULL, '2026-06-08 22:10:30', '2026-06-15 04:38:04'),
(13, 2, 1, 'Request: multiple workspace support', 'Allow users to manage multiple workspaces from the same account, with separate feedback boards for each team.', 'planned', 48, 52, 4, 16, 1800, 0, NULL, '2026-06-13 22:10:30', '2026-06-15 01:10:34'),
(14, 4, 5, 'Remove forced email confirmation', 'Some users prefer to explore the product before confirming their email address. Forcing confirmation immediately reduces conversion.', 'open', -32, 10, 42, 18, 1200, 0, NULL, '2026-06-11 21:10:30', '2026-06-15 01:10:34'),
